pub fn mini_receive(
    proc_table: &mut [Proc; N_PROC_SLOTS],
    priv_table: &mut [Priv; NR_SYS_PROCS],
    caller_nr: ProcNr,
    src_e: Endpoint,
    user_msg_va: u64,
    flags: RecvFlags,
