1	// Assembles the per-arch entry path and exception vectors into the kernel.
2	//
3	// .S files go through clang (cross-targeted at the kernel triple) and the
4	// resulting .o files are passed straight to the linker via cargo:rustc-link-arg.
5	// We deliberately *avoid* the cc crate's static-library packaging because the
6	// linker's archive member resolution wouldn't pull in `_start` (it's only
7	// referenced via the linker-script `ENTRY` directive, not from any Rust
8	// symbol). Direct .o linkage sidesteps that, and it also dodges the
9	// macOS-ar/ELF-object mismatch entirely.
10	
11	use std::path::PathBuf;
12	use std::process::Command;
13	
14	fn main() {
15	    // Host builds (cargo check / cargo test on macOS or Linux) compile the
16	    // kernel crate as a no-op (main.rs gates every real module on
17	    // `target_os = "none"`). Skip assembly entirely for those — the ELF .o
18	    // files clang would produce here aren't link-compatible with the
19	    // host's mach-o or glibc-flavored ELF and would only break tests.
20	    let target_os = std::env::var("CARGO_CFG_TARGET_OS").unwrap_or_default();
21	    if target_os != "none" {
22	        return;
23	    }
24	
25	    let arch =
26	        std::env::var("CARGO_CFG_TARGET_ARCH").expect("CARGO_CFG_TARGET_ARCH unset");
27	    let out_dir = PathBuf::from(std::env::var_os("OUT_DIR").expect("OUT_DIR unset"));
28	
29	    match arch.as_str() {
30	        "aarch64" => {
31	            let sources = [
32	                "src/arch/aarch64/entry.S",
33	                "src/arch/aarch64/vectors.S",
34	                "src/arch/aarch64/trap.S",
35	                "src/arch/aarch64/interrupt.S",
36	                "src/arch/aarch64/user_stub.S",
37	            ];
38	            for src in &sources {
39	                println!("cargo:rerun-if-changed={src}");
40	                let stem = std::path::Path::new(src)
41	                    .file_stem()
42	                    .unwrap()
43	                    .to_string_lossy();
44	                let obj = out_dir.join(format!("{stem}.o"));
45	                let status = Command::new("clang")
46	                    .args([
47	                        "--target=aarch64-unknown-none",
48	                        "-ffreestanding",
49	                        "-c",
50	                        src,
51	                        "-o",
52	                    ])
53	                    .arg(&obj)
54	                    .status()
55	                    .expect("failed to spawn clang");
56	                if !status.success() {
57	                    panic!("clang failed assembling {src}");
58	                }
59	                println!("cargo:rustc-link-arg={}", obj.display());
60	            }
61	            println!("cargo:rerun-if-changed=src/arch/aarch64/linker.ld");
62	        }
63	        "x86_64" => {
64	            // Phase 8 territory -- nothing to assemble yet.
65	        }
66	        other => panic!("unsupported target arch: {other}"),
67	    }
68	}
69

