1	//! Static process and privilege tables, plus the boot-image table that
2	//! drives initial population.
3	//!
4	//! Storage uses `UnsafeCell<[T; N]>` wrapped in a `Sync` newtype: slice 2.2
5	//! runs on one CPU with interrupts masked, so a `Mutex` would buy nothing
6	//! over `unsafe` accessors that document the single-threaded invariant.
7	//! Slice 2.4 (timer + preemption) will revisit this — at that point we'll
8	//! need a per-table lock or a percpu pattern, not before.
9	
10	use core::cell::UnsafeCell;
11	
12	use minix4_kernel_shared::callnr::NR_KERN_CALLS_PHASE2;
13	use minix4_kernel_shared::com::{
14	    ASYNCM, CLOCK, DS_PROC_NR, HARDWARE, IDLE, INIT_PROC_NR, MEM_PROC_NR, MFS_PROC_NR,
15	    NR_BOOT_PROCS, NR_PROCS, NR_SYS_PROCS, NR_TASKS, PFS_PROC_NR, PM_PROC_NR, RS_PROC_NR,
16	    SCHED_PROC_NR, SYSTEM, TTY_PROC_NR, VFS_PROC_NR, VM_PROC_NR, boot_endpoint,
17	};
18	use minix4_kernel_shared::{PrivId, ProcNr};
19	
20	use super::flags::{
21	    BILLABLE, CSK_T, PREEMPTIBLE, ROOT_SYS_PROC, RTS_NO_PRIV, SRV_T, SYS_PROC, TSK_T,
22	    VM_SYS_PROC,
23	};
24	use super::priv_struct::{IPC_MAP_CHUNKS, K_CALL_MASK_CHUNKS, Priv};
25	use super::proc_struct::{PROC_NAME_LEN, Proc};
26	
27	/// Total slots in the process table: kernel tasks plus user-process room.
28	pub const N_PROC_SLOTS: usize = NR_TASKS + NR_PROCS;
29	
30	// ---------------------------------------------------------------------------
31	// Scheduling constants (slice 2.4 expands these into full bands).
32	// ---------------------------------------------------------------------------
33	
34	/// Highest scheduler priority — reserved for kernel tasks.
35	pub const TASK_Q: u8 = 0;
36	/// Default priority for the root system process (RS).
37	pub const RS_Q: u8 = 4;
38	/// Default priority for the VM server.
39	pub const VM_Q: u8 = 4;
40	/// Default priority for ordinary boot servers.
41	pub const SRV_Q: u8 = 8;
42	/// Default priority for `init`.
43	pub const INIT_Q: u8 = 8;
44	/// Lowest priority — the idle task only.
45	pub const IDLE_Q: u8 = 15;
46	
47	/// Default scheduling quantum for user-class servers (ms).
48	pub const SRV_QUANTUM_MS: u32 = 200;
49	
50	// ---------------------------------------------------------------------------
51	// Static storage.
52	// ---------------------------------------------------------------------------
53	
54	#[repr(transparent)]
55	struct ProcStorage(UnsafeCell<[Proc; N_PROC_SLOTS]>);
56	// SAFETY: slice 2.2 runs single-threaded with interrupts masked; concurrent
57	// access to PROC_TABLE is impossible. Future slices that enable preemption
58	// must wrap this in a proper lock before keeping this `unsafe impl`.
59	unsafe impl Sync for ProcStorage {}
60	
61	#[repr(transparent)]
62	struct PrivStorage(UnsafeCell<[Priv; NR_SYS_PROCS]>);
63	// SAFETY: same single-threaded invariant as ProcStorage.
64	unsafe impl Sync for PrivStorage {}
65	
66	static PROC_TABLE: ProcStorage = ProcStorage(UnsafeCell::new(
67	    [const { Proc::EMPTY }; N_PROC_SLOTS],
68	));
69	static PRIV_TABLE: PrivStorage = PrivStorage(UnsafeCell::new(
70	    [const { Priv::EMPTY }; NR_SYS_PROCS],
71	));
72	
73	/// Map a [`ProcNr`] to its index in the process table.
74	///
75	/// Kernel tasks (negative `nr`) land in slots `[0, NR_TASKS)`; user processes
76	/// land in `[NR_TASKS, N_PROC_SLOTS)`. Returns `None` if `nr` is outside the
77	/// allocated range.
78	pub const fn proc_index(nr: ProcNr) -> Option<usize> {
79	    let n = nr.get();
80	    let shifted = n + NR_TASKS as i32;
81	    if shifted < 0 || (shifted as usize) >= N_PROC_SLOTS {
82	        None
83	    } else {
84	        Some(shifted as usize)
85	    }
86	}
87	
88	/// Map a [`PrivId`] to its index in the privilege table.
89	pub const fn priv_index(id: PrivId) -> Option<usize> {
90	    let n = id.as_usize();
91	    if n >= NR_SYS_PROCS { None } else { Some(n) }
92	}
93	
94	// ---------------------------------------------------------------------------
95	// Boot image.
96	// ---------------------------------------------------------------------------
97	
98	struct BootEntry {
99	    nr: ProcNr,
100	    name: &'static [u8],
101	    priv_flags: u16,
102	    trap_mask: u16,
103	    priority: u8,
104	    quantum_ms: u32,
105	    runnable: bool,
106	}
107	
108	const N_IMAGE: usize = NR_TASKS + NR_BOOT_PROCS;
109	const _: () = assert!(N_IMAGE == 16);
110	
111	static IMAGE: [BootEntry; N_IMAGE] = [
112	    // --- Kernel tasks (always runnable) -----------------------------------
113	    BootEntry { nr: ASYNCM,   name: b"asyncm",   priv_flags: SYS_PROC,            trap_mask: TSK_T, priority: TASK_Q, quantum_ms: 0, runnable: true },
114	    BootEntry { nr: IDLE,     name: b"idle",     priv_flags: SYS_PROC | BILLABLE, trap_mask: TSK_T, priority: IDLE_Q, quantum_ms: 0, runnable: true },
115	    BootEntry { nr: CLOCK,    name: b"clock",    priv_flags: SYS_PROC,            trap_mask: CSK_T, priority: TASK_Q, quantum_ms: 0, runnable: true },
116	    BootEntry { nr: SYSTEM,   name: b"system",   priv_flags: SYS_PROC,            trap_mask: CSK_T, priority: TASK_Q, quantum_ms: 0, runnable: true },
117	    BootEntry { nr: HARDWARE, name: b"hardware", priv_flags: SYS_PROC,            trap_mask: TSK_T, priority: TASK_Q, quantum_ms: 0, runnable: true },
118	
119	    // --- Boot servers (blocked on RTS_NO_PRIV until slice 2.6 loads ELFs) -
120	    BootEntry { nr: PM_PROC_NR,    name: b"pm",    priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
121	    BootEntry { nr: VFS_PROC_NR,   name: b"vfs",   priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
122	    BootEntry { nr: RS_PROC_NR,    name: b"rs",    priv_flags: SYS_PROC | PREEMPTIBLE | ROOT_SYS_PROC, trap_mask: SRV_T, priority: RS_Q,   quantum_ms: SRV_QUANTUM_MS, runnable: false },
123	    BootEntry { nr: MEM_PROC_NR,   name: b"memory",priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
124	    BootEntry { nr: TTY_PROC_NR,   name: b"tty",   priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
125	    BootEntry { nr: DS_PROC_NR,    name: b"ds",    priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
126	    BootEntry { nr: MFS_PROC_NR,   name: b"mfs",   priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
127	    BootEntry { nr: VM_PROC_NR,    name: b"vm",    priv_flags: SYS_PROC | PREEMPTIBLE | VM_SYS_PROC,   trap_mask: SRV_T, priority: VM_Q,   quantum_ms: SRV_QUANTUM_MS, runnable: false },
128	    BootEntry { nr: PFS_PROC_NR,   name: b"pfs",   priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
129	    BootEntry { nr: SCHED_PROC_NR, name: b"sched", priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: SRV_Q,  quantum_ms: SRV_QUANTUM_MS, runnable: false },
130	    BootEntry { nr: INIT_PROC_NR,  name: b"init",  priv_flags: SYS_PROC | PREEMPTIBLE,                 trap_mask: SRV_T, priority: INIT_Q, quantum_ms: SRV_QUANTUM_MS, runnable: false },
131	];
132	
133	// ---------------------------------------------------------------------------
134	// Access helpers. All return raw pointers — callers carry the single-threaded
135	// invariant.
136	// ---------------------------------------------------------------------------
137	
138	/// SAFETY: caller must ensure no other reference into `PROC_TABLE` exists.
139	pub(crate) unsafe fn proc_slot_mut(nr: ProcNr) -> Option<&'static mut Proc> {
140	    let idx = proc_index(nr)?;
141	    // SAFETY: `idx` is in-range; single-threaded boot context.
142	    let arr = unsafe { &mut *PROC_TABLE.0.get() };
143	    Some(&mut arr[idx])
144	}
145	
146	/// SAFETY: caller must ensure no exclusive reference into `PROC_TABLE` exists.
147	pub(crate) unsafe fn proc_table_ref() -> &'static [Proc; N_PROC_SLOTS] {
148	    // SAFETY: single-threaded boot context.
149	    unsafe { &*PROC_TABLE.0.get() }
150	}
151	
152	/// Borrow `PROC_TABLE` mutably as a slice. Used by `ipc::do_ipc` to hand a
153	/// single `&mut [Proc]` down through every IPC primitive — avoiding the
154	/// two-`&mut`-from-one-`UnsafeCell` hazard that arises if each primitive
155	/// re-borrows individual slots via `proc_slot_mut`.
156	///
157	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
158	/// invariant and must not hold any other reference into `PROC_TABLE`
159	/// while the returned borrow is live.
160	pub(crate) unsafe fn proc_table_mut_slice() -> &'static mut [Proc; N_PROC_SLOTS] {
161	    // SAFETY: forwarded — caller's invariants.
162	    unsafe { &mut *PROC_TABLE.0.get() }
163	}
164	
165	/// SAFETY: caller must ensure no other reference into `PRIV_TABLE` exists.
166	pub(crate) unsafe fn priv_slot_mut(id: PrivId) -> Option<&'static mut Priv> {
167	    let idx = priv_index(id)?;
168	    // SAFETY: `idx` is in-range; single-threaded boot context.
169	    let arr = unsafe { &mut *PRIV_TABLE.0.get() };
170	    Some(&mut arr[idx])
171	}
172	
173	/// SAFETY: caller must ensure no exclusive reference into `PRIV_TABLE` exists.
174	pub(crate) unsafe fn priv_table_ref() -> &'static [Priv; NR_SYS_PROCS] {
175	    // SAFETY: single-threaded boot context.
176	    unsafe { &*PRIV_TABLE.0.get() }
177	}
178	
179	/// Borrow `PRIV_TABLE` mutably as a slice. Companion of
180	/// [`proc_table_mut_slice`] — `ipc::do_ipc` materializes both at once and
181	/// passes them down to the per-primitive handlers.
182	///
183	/// SAFETY: caller must hold the single-threaded-boot / IRQ-masked
184	/// invariant and must not hold any other reference into `PRIV_TABLE`
185	/// while the returned borrow is live.
186	pub(crate) unsafe fn priv_table_mut_slice() -> &'static mut [Priv; NR_SYS_PROCS] {
187	    // SAFETY: forwarded — caller's invariants.
188	    unsafe { &mut *PRIV_TABLE.0.get() }
189	}
190	
191	// ---------------------------------------------------------------------------
192	// Boot-time population.
193	// ---------------------------------------------------------------------------
194	
195	/// Populate `PROC_TABLE` and `PRIV_TABLE` from `IMAGE`.
196	///
197	/// Called exactly once from `kmain` during boot. Slice 2.4's scheduler will
198	/// assume one-shot init; double-calling would clobber any RTS bits the
199	/// scheduler has set since.
200	pub fn init() {
201	    init_empty_slots();
202	    init_boot_image();
203	}
204	
205	fn init_empty_slots() {
206	    // Give every slot a valid (nr, endpoint) so that index-based traversal
207	    // never sees a stale zero `nr` after `Proc::EMPTY` initialization.
208	    for i in 0..N_PROC_SLOTS {
209	        let nr = ProcNr::new(i as i32 - NR_TASKS as i32);
210	        // SAFETY: index in-range; single-threaded boot context; no other
211	        // references into PROC_TABLE exist at this point in `init`.
212	        let p = unsafe { proc_slot_mut(nr) }.expect("proc index in range");
213	        p.nr = nr;
214	        p.endpoint = boot_endpoint(nr);
215	        // EMPTY left rts_flags = RTS_SLOT_FREE — leave it that way.
216	    }
217	
218	    for i in 0..NR_SYS_PROCS {
219	        // SAFETY: index in-range; single-threaded boot context.
220	        let pr = unsafe { priv_slot_mut(PrivId::new(i as u16)) }
221	            .expect("priv index in range");
222	        pr.id = PrivId::new(i as u16);
223	    }
224	}
225	
226	fn init_boot_image() {
227	    // Active priv-slot count after population — the IPC bitmap for SRV_T
228	    // entries needs to enumerate every active slot.
229	    let n_active = N_IMAGE as u16;
230	
231	    for (slot, entry) in IMAGE.iter().enumerate() {
232	        let priv_id = PrivId::new(slot as u16);
233	        populate_priv(priv_id, entry, n_active);
234	        populate_proc(priv_id, entry);
235	    }
236	}
237	
238	fn populate_priv(id: PrivId, entry: &BootEntry, n_active: u16) {
239	    // SAFETY: priv index < NR_SYS_PROCS; single-threaded boot context; no
240	    // overlapping reference into PRIV_TABLE held across the call.
241	    let pr = unsafe { priv_slot_mut(id) }.expect("priv slot in range");
242	    pr.id = id;
243	    pr.proc_nr = Some(entry.nr);
244	    pr.flags = entry.priv_flags;
245	    pr.trap_mask = entry.trap_mask;
246	
247	    if entry.trap_mask == SRV_T {
248	        // SRV_T privs can send to every active slot. Set bits [0, n_active).
249	        fill_bits(&mut pr.ipc_to, n_active as usize);
250	        // SRV_T privs can issue every kernel call defined so far.
251	        // TODO(slice 2.6): widen as new kernel calls land — this bound must
252	        // track the highest `SYS_*` number, not the Phase-2 count.
253	        fill_bits(&mut pr.k_call_mask, NR_KERN_CALLS_PHASE2);
254	    }
255	    // Kernel-task slots leave ipc_to and k_call_mask zeroed.
256	
257	    pr.sig_mgr = boot_endpoint(RS_PROC_NR);
258	    pr.notify_pending.fill(0);
259	    pr.asyn_pending.fill(0);
260	}
261	
262	fn populate_proc(priv_id: PrivId, entry: &BootEntry) {
263	    // SAFETY: proc index in-range; single-threaded boot context; no
264	    // overlapping reference into PROC_TABLE held across the call.
265	    let p = unsafe { proc_slot_mut(entry.nr) }.expect("proc slot in range");
266	    p.priv_id = Some(priv_id);
267	    p.priority = entry.priority;
268	    p.quantum_ms = entry.quantum_ms;
269	    p.quantum_left = entry.quantum_ms as u64;
270	    p.endpoint = boot_endpoint(entry.nr);
271	    p.nr = entry.nr;
272	
273	    // Copy name into the fixed-width field (truncates silently at PROC_NAME_LEN).
274	    let n = core::cmp::min(entry.name.len(), PROC_NAME_LEN - 1);
275	    p.name[..n].copy_from_slice(&entry.name[..n]);
276	    p.name[n..].fill(0);
277	
278	    let rts = if entry.runnable { 0 } else { RTS_NO_PRIV };
279	    p.rts_flags
280	        .store(rts, core::sync::atomic::Ordering::Relaxed);
281	}
282	
283	/// Set the lowest `n` bits in a `u32` bitmap.
284	fn fill_bits(map: &mut [u32], n: usize) {
285	    for i in 0..n {
286	        let word = i / 32;
287	        let bit = i % 32;
288	        if word < map.len() {
289	            map[word] |= 1 << bit;
290	        }
291	    }
292	}
293	
294	// Compile-time sanity that the bitmap sizing came out as expected.
295	const _: () = assert!(IPC_MAP_CHUNKS == 2);
296	const _: () = assert!(K_CALL_MASK_CHUNKS == 1);
297	
298	/// Number of slots in `PROC_TABLE` (for the dump helper).
299	pub const fn n_proc_slots() -> usize {
300	    N_PROC_SLOTS
301	}
302	
303	/// Number of slots in `IMAGE` (for the dump helper).
304	pub const fn n_image_slots() -> usize {
305	    N_IMAGE
306	}
307

