/// Permission gate: returns `ETRAPDENIED` if the caller's `trap_mask`
/// doesn't permit `call_nr`, otherwise runs `f` and returns its result.
#[inline]
fn trap_gate(trap_mask: u16, call_nr: i32, f: impl FnOnce() -> i32) -> i32 {
    // call_nr is one of the SEND/RECEIVE/.../SENDA constants here — all
    // ≤ SENDA(16), so `1 << call_nr` fits in u16 (SENDA's bit is the
    // top valid bit) and never shifts past the mask width.
    if trap_mask & (1u16 << call_nr) == 0 {
        return ETRAPDENIED;
    }
    f()
}

